import{G as i}from"./chunks/shared-links.CZ5QUsOH.js";import{C as t,o as a,c as s,j as o,a as l,E as n,k as c,a2 as d}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Введение","description":"","frontmatter":{},"headers":[],"relativePath":"ru/introduction.md","filePath":"ru/introduction.md"}'),p={name:"ru/introduction.md"},m=Object.assign(p,{setup(h){return(g,e)=>{const r=t("YoutubePlayer");return a(),s("div",null,[e[0]||(e[0]=o("h1",{id:"введение",tabindex:"-1"},[o("i",{class:"ph ph-hand-waving"}),l(" Введение "),o("a",{class:"header-anchor",href:"#введение","aria-label":'Permalink to "<i class="ph ph-hand-waving"></i> Введение"'},"​")],-1)),n(r,{src:c(i).youtubeVideo},null,8,["src"]),e[1]||(e[1]=d('<p><strong>Web Adaptive Performance (WebAP)</strong> — это инструмент для динамической оптимизации Unity WebGL-приложений.</p><p>Он помогает найти баланс между качеством картинки и стабильным FPS на разных устройствах: от мощных ПК до слабых смартфонов. Вместо жестких лимитов, плагин анализирует тайминги кадров в реальном времени. Находит причину просадок, плавно снижает нагрузку до стабилизации, а при появлении запаса мощности возвращает качество обратно.</p><div class="tip custom-block"><p class="custom-block-title">Адаптация под устройство</p><p>Установите максимальные настройки качества в Unity по умолчанию. Плагин сам снизит их в рантайме, если текущее устройство не справляется с нагрузкой.</p></div><h2 id="почему-именно-webap" tabindex="-1">Почему именно WebAP? <a class="header-anchor" href="#почему-именно-webap" aria-label="Permalink to &quot;Почему именно WebAP?&quot;">​</a></h2><p><strong><i class="ph-bold ph-x"></i> Почему не официальный пакет Adaptive Performance?</strong><br> Официальный пакет от Unity мощный инструмент, но он фундаментально несовместим с WebGL. У него есть два типа провайдеров, и оба разбиваются об ограничения браузера:</p><ol><li><strong>Нативные провайдеры (Android):</strong> Опираются на системные API для получения статусов перегрева (Thermal Headroom) и управления частотами. Браузерная песочница блокирует любой доступ к железу, делая этот подход невозможным. Новые веб-стандарты (вроде <em>Compute Pressure API</em>) видят только CPU и не дают точных данных для 3D-графики.</li><li><strong>Basic Provider:</strong> Кроссплатформенный математический провайдер Unity. Он опирается на <code>FrameTimingManager</code>. Однако для его работы движку требуются высокоточные аппаратные таймеры GPU, которые в браузерах принудительно заблокированы или сильно зашумлены из соображений безопасности (защита от атак <em>Spectre/Meltdown</em>). Из-за этого официальный Basic Provider в WebGL физически не инициализируется.</li></ol><p><strong><i class="ph-bold ph-check"></i> Решение WebAP:</strong> Мы создали архитектуру, заточенную исключительно под специфику веба. WebAP также использует <code>FrameTimingManager</code>, но вместо жесткой зависимости от заблокированных GPU-таймеров, плагин применяет безопасный эвристический анализ. Он обходит браузерные аномалии (такие как искажения метрик из-за <code>setTimeout</code> в Emscripten) и использует чистую математику для вычисления узких мест (CPU vs GPU). Это дает вам систему оптимизации AAA-уровня, которая легально и стабильно работает в любом браузере.</p><p><strong><i class="ph-bold ph-x"></i> Почему не обычные скрипты масштабирования?</strong><br> Классические решения просто снижают разрешение экрана при любых лагах. Это бесполезно, если приложение тормозит из-за расчетов CPU (физика, скрипты, логика), а не из-за рендера.</p><p><strong><i class="ph-fill ph-check-fat"></i> Как работает WebAP:</strong></p><ul><li><i class="ph-fill ph-brain"></i> <strong>Поиск узких мест (Bottlenecks)</strong><br> Плагин математически определяет, во что уперся кадр: в CPU или GPU. Если тормозит физика — система упростит физику, не снижая разрешение экрана. Для этого предусмотрено более 12 независимых скейлеров (Shadows, LOD, Layer Culling и другие).</li><li><i class="ph-fill ph-hand-palm"></i> <strong>Anti Yo-Yo System</strong><br> Решает частую проблему динамического разрешения, когда качество постоянно скачет вверх-вниз. Если после улучшения графики FPS сразу падает, система временно блокирует дальнейшие повышения.</li><li><i class="ph-fill ph-layout"></i> <strong>Сохранение четкости UI</strong><br> Если вы выберете режим масштабирования через <code>RenderTexture</code>, разрешение 3D-мира будет снижаться, но интерфейс останется в нативном разрешении браузера. Кастомный компонент <code>WebScaledPhysicsRaycaster</code> автоматически пересчитает координаты лучей, чтобы клики по 3D-объектам работали корректно при любом сжатии кадра.</li><li><i class="ph-fill ph-lightning"></i> <strong>Zero-GC архитектура</strong><br> Весь проект спроектирован с учетом жесткой экономии памяти. Ядро использует кольцевые буферы и не делает аллокаций в цикле <code>Update</code>, поэтому плагин не провоцирует сборщик мусора (Garbage Collector).</li><li><i class="ph-fill ph-broom"></i> <strong>Строгая чистота билда</strong><br> Многие ассеты засоряют релизную сборку, помещая свои префабы и текстуры в папку <code>Resources</code> (из-за чего движок принудительно включает их в билд). Архитектура WebAP лишена этой ошибки. Весь инструментарий и UI Дашборда будут автоматически вырезаны при компиляции, если вы не добавили их на сцену. В итоговый проект попадает только легковесное ядро.</li><li><i class="ph-fill ph-gear"></i> <strong>Plug-and-Play интеграция</strong><br> Настройки собраны в едином интерфейсе внутри <em>Project Settings</em>. Плагин автоматически инжектится в билд — вам не нужно вручную размещать префабы менеджеров на сценах.</li></ul><h2 id="совместимость" tabindex="-1">Совместимость <a class="header-anchor" href="#совместимость" aria-label="Permalink to &quot;Совместимость&quot;">​</a></h2><ul><li><strong>Версия Unity:</strong> <code>2020.3 LTS</code> и выше. Плагин использует современные API и автоматически подхватывает новые фичи движка (например, поддержку <code>Mesh LOD Threshold</code> для Unity 6000.2+).</li><li><strong>Render Pipelines:</strong> Бесшовная поддержка как Built-in Render Pipeline (BRP), так и Universal Render Pipeline (URP).</li></ul>',12))])}}});export{u as __pageData,m as default};
